// Format DB report from merged $input.all() — no cross-node refs.
// Each upstream Postgres query tags its rows with `kind`, so we filter
// by kind here. `onError: continueRegularOutput` on each Postgres means
// a missing extension or permission error becomes an empty stream, not
// a workflow-level failure.
const items = $input.all().map(i => i.json);

const dbInfo = items.find(r => r && r.kind === 'db_info') ?? {};
const tables = items.filter(r => r && r.kind === 'table');
const slow = items.filter(r => r && r.kind === 'slow_query');

const tableLines = tables.map(t =>
  `  \`${t.table_name}\` — ${t.total_size} (${Number(t.row_count).toLocaleString()} rows)`
).join('\n') || '  —';

const slowLines = slow.length
  ? slow.map(q => `  ${q.avg_ms}ms (×${q.calls}) \`${q.query_preview}\``).join('\n')
  : '  pg\\_stat\\_statements не встановлено або немає даних';

const text = [
  `🗄 *DB: ${dbInfo.db_name ?? 'unknown'}*`,
  `📦 Розмір: \`${dbInfo.db_size ?? 'unknown'}\``,
  `👥 Користувачів: ${dbInfo.user_count ?? '—'}`,
  `💳 Транзакцій Mono: ${dbInfo.tx_count != null ? Number(dbInfo.tx_count).toLocaleString() : '—'}`,
  `🔔 Push-підписок: ${dbInfo.active_push_subs ?? '—'}`,
  ``,
  `📋 *Топ таблиці:*`,
  tableLines,
  ``,
  `🐢 *Повільні запити:*`,
  slowLines,
].join('\n');

return [{ json: { text } }];

// ADR-0038, Wave 3 §3.2 — pre-Telegram step that:
//   1. Builds a stable `alertId` so n8n retries no-op via
//      ON CONFLICT DO NOTHING server-side.
//   2. Carries forward the upstream item as `summary` so that the
//      Telegram text + ack-row are computed from a single source.
// Output is consumed by both POST /api/internal/alerts/post
// (idempotency) and the downstream Telegram node (text +
// reply_markup callback_data).
const item = $input.first()?.json ?? {};
const alertId = `${$workflow.id || 'unknown'}:${$execution.id || 'unknown'}:db-health`;
const summary = `DB health weekly digest — db=${$('DB size & counts').first()?.json?.db_name ?? 'unknown'}, size=${$('DB size & counts').first()?.json?.db_size ?? 'unknown'}`;
return [{
  json: {
    alertId,
    summary,
    upstream: item,
    metadata: {
      workflowId: $workflow.id || 'unknown',
      executionId: $execution.id || 'unknown',
      dbName: $('DB size & counts').first()?.json?.db_name ?? null,
      dbSize: $('DB size & counts').first()?.json?.db_size ?? null,
      userCount: Number($('DB size & counts').first()?.json?.user_count) || null,
      txCount: Number($('DB size & counts').first()?.json?.tx_count) || null,
    },
  },
}];
